rn nil\n}\n\nfunc (r RealPodControl) DeletePod(ctx context.Context, namespace string, podID string, object runtime.Object) error {\n\taccessor, err := meta.Accessor(object)\n\tif err != nil {\n\t\treturn fmt.Errorf(\"object does not have ObjectMeta, %v\", err)\n\t}\n\tlogger := klog.FromContext(ctx)\n\tlogger.V(2).Info(\"Deleting pod\", \"controller\", accessor.GetName(), \"pod\", klog.KRef(namespace, podID))", "numLines": 150, "startLine": 459, "totalLines": 1287}}

